typedef struct _HID_COLLECTION_INFORMATION {
ULONG   DescriptorSize;   BOOLEAN Polled;
UCHAR   Reserved1[1];
USHORT  VendorID;   USHORT  ProductID;
USHORT  VersionNumber;
} HID_COLLECTION_INFORMATION, *PHID_COLLECTION_INFORMATION; 成员
DescriptorSize
指定集合 预分析数据的大小（以字节为单位）。 Polled
指示如果 TRUE，则 HID 类驱动程序必须轮询设备才能接收数据。 否则，如果 轮询FALSE，则
设备使用异步中断向主机发出信号，表明设备有 HID 报告要发送到主机。 Reserved1[1]
保留供内部系统使用。 VendorID
指定 HID 设备的供应商 ID。 ProductID
指定 HID 设备的产品 ID。 VersionNumber
指定 HID 设备的制造商修订号。

typedef struct _HID_DESCRIPTOR {
UCHAR                     bLength;
UCHAR                     bDescriptorType;
USHORT                    bcdHID;       UCHAR                     bCountry;
UCHAR                     bNumDescriptors;   struct {
UCHAR  bReportType;         USHORT wReportLength;   } _HID_DESCRIPTOR_DESC_LIST;
_HID_DESCRIPTOR_DESC_LIST DescriptorList[1];} HID_DESCRIPTOR, *PHID_DESCRIPTOR;
成员 bLength
bDescriptorType
bcdHID bCountry
bNumDescriptors
_HID_DESCRIPTOR_DESC_LIST
_HID_DESCRIPTOR_DESC_LIST.bReportType_HID_DESCRIPTOR_DESC_LIST.wReportLength
[1] DescriptorList[1] 言论
HID 类驱动程序使用 IOCTL_HID_GET_DEVICE_DESCRIPTOR 请求从 HID 微型驱动程序获取设备的 HID 描述符。
有关 HID 描述符的信息，请参阅位于 USB 实现者论坛网站
准 人机接口设备类定义（HID）。

typedef struct _HID_DEVICE_EXTENSION {   PDEVICE_OBJECT PhysicalDeviceObject;   PDEVICE_OBJECT NextDeviceObject;
PVOID          MiniDeviceExtension;
} HID_DEVICE_EXTENSION, *PHID_DEVICE_EXTENSION; 成员
PhysicalDeviceObject
指向 HID 设备的物理设备对象的指针。 NextDeviceObject
指向 HID 设备堆栈中功能设备对象正下方的设备对象的指针。 MiniDeviceExtension
指向设备扩展中特定于微型驱动程序的部分的指针。

typedef struct _HID_XFER_PACKET {   PUCHAR reportBuffer;
ULONG  reportBufferLen;   UCHAR  reportId;
} HID_XFER_PACKET, *PHID_XFER_PACKET;
成员 reportBuffer
指向报表缓冲区的指针。 reportBufferLen
指定报表长度 reportBuffer。 reportId
指定 reportBuffer中包含的报表的报表 ID。 此参数是可选的，如果未指定，则应设置为零。

